import{c as e,a7 as p,y as _,B as $,v as a,D as t}from"./chunks/framework.3cjvm90C.js";const m=JSON.parse('{"title":"扩散模型理论第一课","description":"介绍扩散模型的前向过程与反向去噪过程，对比 GAN 并推导 DDPM 的核心公式。","frontmatter":{"title":"扩散模型理论第一课","description":"介绍扩散模型的前向过程与反向去噪过程，对比 GAN 并推导 DDPM 的核心公式。"},"headers":[],"relativePath":"diffusion/theory.md","filePath":"diffusion/theory.md","lastUpdated":1782456021000}'),r={name:"diffusion/theory.md"};function i(s,l,h,o,n,x){return p(),_("div",null,[...l[0]||(l[0]=[$('<h1 id="扩散模型理论第一课" tabindex="-1">扩散模型理论第一课 <a class="header-anchor" href="#扩散模型理论第一课" aria-label="Permalink to “扩散模型理论第一课”">​</a></h1><p>扩散模型解决的任务类似于生成对抗网络（GANs）以及其他类型的生成模型，如变分自编码器（VAEs）或归一化流（Normalizing Flows）——它们尝试逼近给定领域的概率分布 $q(x)$，并且最重要的是，提供一种从该分布中采样的方法 $x \\sim q(x)$。</p><p>这是通过优化某些参数 $\\theta$（表示为神经网络）来实现的，这些参数导致概率分布 $p_\\theta(x)$。训练的目标是让 $p_\\theta$ 生成的样本 $x$ 与从真实底层分布 $q(x)$ 中抽取的样本相似。</p><h2 id="与-gans-的不同之处" tabindex="-1">与 GANs 的不同之处？ <a class="header-anchor" href="#与-gans-的不同之处" aria-label="Permalink to “与 GANs 的不同之处？”">​</a></h2><ul><li>GANs 通过生成器网络的单次前向传递从潜在向量中产生样本。产生的样本的可能性由鉴别器网络控制，该网络被训练用来区分 $x \\sim q(x)$ 和 $x \\sim p_\\theta(x)$。</li><li>扩散模型使用一个网络，通过多个估计步骤顺序地逼近真实样本 $x \\sim q(x)$ 的近似值。因此，模型的输入和输出通常是相同的维度。</li></ul><h2 id="去噪扩散过程的机制" tabindex="-1">去噪扩散过程的机制 <a class="header-anchor" href="#去噪扩散过程的机制" aria-label="Permalink to “去噪扩散过程的机制”">​</a></h2><p>去噪扩散过程由两个方向的一系列步骤组成，对应于样本中信息的破坏和创建。</p><h3 id="前向过程" tabindex="-1">前向过程 <a class="header-anchor" href="#前向过程" aria-label="Permalink to “前向过程”">​</a></h3><p>在拥有时间步 $t$ 的样本的情况下，可以对前向过程中下一个样本进行估计，由真实分布 $q$ 定义：</p><p>$$ q(x_{t}|x_{t-1})\\tag{1} $$</p><p>通常，可用的是时间步 $0$ 的样本（即干净的样本），并且使用允许轻松高效地表述以下类型的操作是有用的：</p><p>$$ q(x_{t}|x_{0})\\tag{2} $$</p><p>到目前为止，<strong>最常见的</strong>前向过程选择是 <strong>高斯过程</strong>。易于计算并且在各方面都很便利：</p><p>$$ q(x_{t}|x_{t-1}) = \\mathcal{N}(\\sqrt{1-\\beta_t}x_{t-1}, \\beta_t I)\\tag{3} $$</p><p>上述符号意味着 <strong>先前的样本通过 $\\sqrt{1-\\beta_t}$ 的因子缩小</strong> 并且 <strong>添加了额外的高斯噪声</strong>（从均值为零，方差为单位的高斯中采样）乘以 $\\beta_t$。</p><p>此外，$0\\to t$ 步骤也可以很容易地定义为：</p><p>$$ q(x_{t}|x_{0}) = \\mathcal{N}(\\sqrt{\\bar{\\alpha}_t}x_0, (1-\\bar{\\alpha}_t) I) \\tag{4} $$</p><p>其中 $\\alpha_t = 1-\\beta_t$ 且</p>',18),a("p",null,[t("$$ \\bar{\\alpha}"),a("em",{i:"0"},"t=\\prod"),t("^{t}\\alpha_i \\tag{5} $$")],-1),$('<h3 id="反向过程" tabindex="-1">反向过程 <a class="header-anchor" href="#反向过程" aria-label="Permalink to “反向过程”">​</a></h3><p>反向过程旨在恢复样本中的信息，从而允许从分布中生成新的样本。通常，它会从某个高时间步 $t$（通常是 $t=T$，表示扩散链的末端，此时概率分布非常接近纯高斯）开始，并尝试逼近前一个样本 $t-1$ 的分布。</p><p>$$ p_\\theta(x_{t-1}|x_t) $$</p><p>如果扩散步骤足够小，高斯前向过程的反向过程也可以通过高斯来逼近：</p><p>$$ p_\\theta(x_{t-1}|x_t) = \\mathcal{N}(\\mu_\\theta(x_t,t),\\Sigma_\\theta(x_t,t))\\tag{6} $$</p><p>反向过程通常使用神经网络 $\\theta$ 来参数化，神经网络是一个很好的候选者，用于逼近复杂的变换。在许多情况下，可以使用独立于 $x_t$ 的标准差函数 $\\sigma_t$：</p><p>$$ p_\\theta(x_{t-1}|x_t) = \\mathcal{N}(\\mu_\\theta(x_t,t),\\sigma_t^2 I)\\tag{7} $$</p><h2 id="ddpm-去噪扩散概率模型" tabindex="-1">DDPM: 去噪扩散概率模型 <a class="header-anchor" href="#ddpm-去噪扩散概率模型" aria-label="Permalink to “DDPM: 去噪扩散概率模型”">​</a></h2><p><a href="https://arxiv.org/abs/2006.11239" target="_blank" rel="noreferrer">DDPM</a> 是去噪扩散领域的一个流行方法之一。它通过遵循反向过程的所有 <em>T</em> 步骤生成样本。</p><p>当涉及到参数化反向过程分布的均值 $\\mu_\\theta(x_t,t)$ 时，网络可以：</p><ol><li>直接预测它作为 $\\mu_\\theta(x_t,t)$</li><li>预测原始的 $t=0$ 样本 $x_0$，其中</li></ol>',11),a("p",null,[t("$$ \\tilde{\\mu}"),a("em",{"t-1":""},"\\theta = \\frac{\\sqrt{\\bar{\\alpha}"),t(" }\\beta_t}{1-\\bar{\\alpha}"),a("em",{"t-1":""},"t}x_0 + \\frac{\\sqrt{\\alpha_t}(1-\\bar{\\alpha}"),t(")}{1-\\bar{\\alpha}_t}x_t \\tag{8} $$")],-1),a("ol",{start:"3"},[a("li",null,[t("预测添加到样本 $x_0$ 上的 "),a("strong",null,"标准"),t(" 噪声样本 $\\epsilon$（来自单位方差的分布）")])],-1),a("p",null,"$$ x_0=\\frac{1}{\\sqrt{\\bar{\\alpha}_t} }(x_t-\\sqrt{1-\\bar{\\alpha}_t}\\epsilon) \\tag{9} $$",-1),a("p",null,"第三种选择，即网络预测 $\\epsilon$，似乎是最常见的，这就是 DDPM 在采样中所做的事情。这导致 $\\tilde{\\mu}_{\\theta}$ 的新方程，以 $x_t$ 和 $\\epsilon$ 表示：",-1),a("p",null,[t("$$ \\tilde{\\mu}"),a("em",{"t-1":""},"\\theta = \\frac{\\sqrt{\\bar{\\alpha}"),t(" }\\beta_t}{1-\\bar{\\alpha}_t}(\\frac{1}{\\sqrt{\\bar{\\alpha}_t} }(x_t-\\sqrt{1-\\bar{\\alpha}"),a("em",{"t-1":""},"t}\\epsilon)) + \\frac{\\sqrt{\\alpha_t}(1-\\bar{\\alpha}"),t(")}{1-\\bar{\\alpha}_t}x_t \\tag{10} $$")],-1),$('<p>因此，</p><p>$$ \\tilde{\\mu}_\\theta =\\frac{1}{\\sqrt{\\alpha_t} }(x_t-\\frac{\\beta_t}{\\sqrt{1-\\bar{\\alpha}_t} }\\epsilon) \\tag{11} $$</p><p>...这是 DDPM 用于采样的关键方程。</p><h3 id="训练" tabindex="-1">训练 <a class="header-anchor" href="#训练" aria-label="Permalink to “训练”">​</a></h3><p>训练一个模型来预测噪声形状 $\\epsilon$ 是相当直接的。</p><p>在每个训练步骤中：</p><ol><li>使用 <strong>前向过程</strong> 生成一个样本 $x_t \\sim q(x_t|x_0)$，对于从 $[1,T]$ 中均匀采样的 $t$： <ol><li>从均匀分布中采样时间步 $t$，$t \\sim \\mathcal{U}(1,T)$</li><li>从正态高斯中采样 $\\epsilon \\sim \\mathcal{N}(0,1)$</li><li>通过 $x_t = \\sqrt{\\bar{\\alpha}_t}x_0 + \\sqrt{1-\\bar{\\alpha}_t}\\epsilon$ 计算训练中的噪声输入样本</li></ol></li><li><strong>计算噪声的近似值</strong> $\\hat{\\epsilon_t}=p_\\theta(x_t,t)$，使用具有参数 $\\theta$ 的模型</li><li><strong>最小化</strong> $\\epsilon_t$ 和 $\\hat{\\epsilon_t}$ 之间的误差，通过优化参数 $\\theta$</li></ol><h3 id="采样" tabindex="-1">采样 <a class="header-anchor" href="#采样" aria-label="Permalink to “采样”">​</a></h3><p>生成过程从 $t=T$ 开始，通过在扩散过程的最后步骤中采样 $x_T \\sim \\mathcal{N}(0,1)$，该过程由正态高斯建模。</p><p>然后，直到达到 $t=0$，网络对样本中的噪声 $\\tilde{\\epsilon}=p_\\theta(x_t,t)$ 进行预测，然后使用以下方法逼近过程在 $t-1$ 的均值：</p><p>$$ \\tilde{\\mu}_\\theta =\\frac{1}{\\sqrt{\\alpha_t} }(x_t-\\frac{\\beta_t}{\\sqrt{1-\\bar{\\alpha}_t} }\\tilde{\\epsilon})\\tag{12} $$</p><p>因此，下一个样本 $t-1$ 是从高斯分布中采样的，如下所示：</p><p>$$ x_{t-1} \\sim \\mathcal{N}(\\tilde{\\mu}_\\theta,\\sigma_t^2 I)\\tag{13} $$</p><p>...直到达到 $x_0$，在这种情况下，只提取均值 $\\tilde{\\mu}_\\theta$ 作为输出。</p><h2 id="更快采样-ddim-去噪扩散隐式模型" tabindex="-1">(更快采样) DDIM: 去噪扩散隐式模型 <a class="header-anchor" href="#更快采样-ddim-去噪扩散隐式模型" aria-label="Permalink to “(更快采样) DDIM: 去噪扩散隐式模型”">​</a></h2><blockquote><p>警告：如果你查看原始的 DDIM 论文，你会看到符号 $\\alpha_t$ 被用来表示 $\\bar{\\alpha}_t$。为了一致性，这篇笔记中没有进行这样的符号更改。</p></blockquote><p><code>DDPM</code> 反向过程尝试以相反的顺序导航扩散链的 <code>T</code> 步骤。然而，如 (9) 所示，反向过程涉及对干净样本 $x_0$ 的近似。</p><p>如果我们在 (4) 中将 $t-1$ 替换为 $t$：</p>',18),a("p",null,[t("$$ q(x_{t-1}|x_{0}) = \\mathcal{N}(\\sqrt{\\bar{\\alpha}"),a("em",{"t-1":""},"{t-1} }x_0, (1-\\bar{\\alpha}"),t(") I)\\tag{14} $$")],-1),a("p",null,"这将产生",-1),a("p",null,[t("$$ x_{t-1} \\leftarrow \\sqrt{\\bar{\\alpha}"),a("em",{"t-1":""},"{t-1} }x_0 + \\sqrt{1-\\bar{\\alpha}"),t(" } \\epsilon_{t-1}\\tag{15} $$")],-1),a("p",null,"...并且基于前一步 $t$ 测量的特定 $\\epsilon_t$，它可以被重写为：",-1),a("p",null,[t("$$ x_{t-1} \\leftarrow \\sqrt{\\bar{\\alpha}"),a("em",{"t-1":""},"{t-1} }x_0 + \\sqrt{1-\\bar{\\alpha}"),t("-\\sigma_t^2} \\epsilon_{t} + \\sigma_t \\epsilon\\tag{16} $$")],-1),a("p",null,"通常，$\\sigma_t$ 被设置为：",-1),a("p",null,[t("$$ \\sigma_t^2 = \\tilde{\\beta}"),a("em",{"t-1":""},"t = \\frac{1-\\bar{\\alpha}"),t(" }{1-\\bar{\\alpha}_t}\\beta_t\\tag{17} $$")],-1),$('<p>进一步，我们可以引入一个新参数 $\\eta$ 来控制随机组成部分的幅度：</p><p>$$\\sigma_t^2 = \\eta \\tilde{\\beta}_t \\tag{18}$$</p><p>正如在原始的 <a href="https://arxiv.org/abs/2010.02502" target="_blank" rel="noreferrer">DDIM 论文</a> 中发现的，设置 $\\eta=0$ 在应用较少的反向过程步骤时特别有益，并且该特定类型的过程被称为 <strong>去噪扩散隐式模型（DDIM）</strong>。当 $\\eta=1$ 时，上述公式仍然与 DDPM 一致。</p><p>那么，如何以相反的方向导航反向链呢？首先，定义一个较少步骤的序列 $S$ 作为前向过程原始时间步骤的子集 ${\\tau_1, \\tau_2, ..., \\tau_S}$。然后，基于 (16) 进行采样。</p><p>在每一步中：</p><ol><li>预测 $x_0$</li><li>计算当前 $x_t$ 的方向</li><li>（如果不是 DDIM）为了随机功能注入一些噪声</li></ol><p>通常可以假设 DDIM：</p><ul><li>在较少的步骤中提供更好的样本质量</li><li>允许起始噪声 $x_T$ 和生成样本 $x_0$ 之间的确定性匹配</li><li>对于大量的步骤（例如 1000 步）表现不如 DDPM</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>扩散模型通过训练一个神经网络来预测噪声样本 $\\epsilon$，从而生成高质量的图像样本。这些模型与 GANs 不同，它们通过一系列估计步骤逐步逼近真实样本的近似值，而不是通过单一的前向传递生成样本。</p><p>扩散过程包括前向过程和反向过程。在前向过程中，通过逐步添加高斯噪声将干净样本转化为噪声样本。而在反向过程中，模型则尝试去除噪声，逐步恢复出干净的样本。</p><p>DDPM（去噪扩散概率模型）是扩散模型的一种，它通过遵循反向过程的所有步骤来生成样本。在参数化反向过程的均值时，网络可以预测原始样本、预测噪声样本，或者直接预测均值。</p><p>DDIM（去噪扩散隐式模型）是 DDPM 的一种变体，它在较少的步骤中提供更好的样本质量，并且允许起始噪声和生成样本之间的确定性匹配。DDIM 通过引入一个控制随机组成部分幅度的新参数 $\\eta$ 来实现这一点。</p><p>扩散模型的训练相对直接，它涉及到生成噪声样本、计算噪声的近似值，并通过优化参数来最小化误差。采样过程从扩散过程的最后步骤开始，逐步预测噪声并恢复出干净的样本。</p><p>扩散模型在图像生成领域展现出了巨大的潜力，它们提供了一种新的生成高质量图像样本的方法。</p>',15)])])}const b=e(r,[["render",i]]);export{m as __pageData,b as default};
